class Solution:
    def largestIsland(self, grid):
        n = len(grid)
        import copy

        def area(g):
            seen = [[False] * n for _ in range(n)]
            best = 0
            for i in range(n):
                for j in range(n):
                    if g[i][j] == 1 and not seen[i][j]:
                        stack = [(i, j)]
                        seen[i][j] = True
                        cnt = 0
                        while stack:
                            x, y = stack.pop()
                            cnt += 1
                            for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                                nx, ny = x + dx, y + dy
                                if 0 <= nx < n and 0 <= ny < n and g[nx][ny] == 1 and not seen[nx][ny]:
                                    seen[nx][ny] = True
                                    stack.append((nx, ny))
                        if cnt > best:
                            best = cnt
            return best

        best = area(grid)
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 0:
                    g2 = copy.deepcopy(grid)
                    g2[i][j] = 1
                    best = max(best, area(g2))
        return best

