class Solution:
    def largestIsland(self, grid):
        n = len(grid)
        label = [[0] * n for _ in range(n)]
        sizes = {}
        cur = 2
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 1 and label[i][j] == 0:
                    stack = [(i, j)]
                    label[i][j] = cur
                    cells = 0
                    while stack:
                        x, y = stack.pop()
                        cells += 1
                        for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                            nx, ny = x + dx, y + dy
                            if 0 <= nx < n and 0 <= ny < n and grid[nx][ny] == 1 and label[nx][ny] == 0:
                                label[nx][ny] = cur
                                stack.append((nx, ny))
                    sizes[cur] = cells
                    cur += 1
        best = max(sizes.values()) if sizes else 0
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 0:
                    seen = set()
                    total = 1
                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = i + dx, j + dy
                        if 0 <= nx < n and 0 <= ny < n:
                            lab = label[nx][ny]
                            if lab and lab not in seen:
                                seen.add(lab)
                                total += sizes[lab]
                    best = max(best, total)
        return best

