var largestIsland = function(grid) {
    const n = grid.length;
    const label = Array.from({length: n}, () => new Array(n).fill(0));
    const sizes = new Map();
    let cur = 2;
    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1 && label[i][j] === 0) {
                const stack = [[i, j]];
                label[i][j] = cur;
                let cells = 0;
                while (stack.length) {
                    const [x, y] = stack.pop();
                    cells++;
                    for (const [dx, dy] of dirs) {
                        const nx = x + dx, ny = y + dy;
                        if (nx >= 0 && nx < n && ny >= 0 && ny < n && grid[nx][ny] === 1 && label[nx][ny] === 0) {
                            label[nx][ny] = cur;
                            stack.push([nx, ny]);
                        }
                    }
                }
                sizes.set(cur, cells);
                cur++;
            }
        }
    }
    let best = 0;
    for (const v of sizes.values()) best = Math.max(best, v);
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 0) {
                const seen = new Set();
                let total = 1;
                for (const [dx, dy] of dirs) {
                    const nx = i + dx, ny = j + dy;
                    if (nx >= 0 && nx < n && ny >= 0 && ny < n) {
                        const lab = label[nx][ny];
                        if (lab && !seen.has(lab)) {
                            seen.add(lab);
                            total += sizes.get(lab);
                        }
                    }
                }
                best = Math.max(best, total);
            }
        }
    }
    return best;
};
